// Start HTML document
let html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>ASIC Miners Catalog ${generatedDate}</title>
  ${css}
</head>
<body>`;

// Header Section
html += `
<div class="header">
  <div class="title">⛏️ ASIC Miners Catalog</div>
  <div class="subtitle">Complete Mining Hardware Reference Guide</div>
  <div class="subtitle">Generated: ${generatedDate}</div>

  <div class="stats-container">
    <div class="stats-box">
      <span class="stats-number">${totalCount}</span>
      <span class="stats-label">Total Models</span>
    </div>
    <div class="stats-box">
      <span class="stats-number">${manufacturers.length}</span>
      <span class="stats-label">Manufacturers</span>
    </div>
  </div>
</div>
`;

// Table of Contents
html += `
<div class="toc">
  <div class="toc-title">📋 Table of Contents</div>
  <div class="toc-grid">
`;

manufacturers.forEach((mfg, index) => {
  const count = groupedMiners[mfg].length;
  html += `
    <div class="toc-item">
      <span class="toc-item-name">${index + 1}. ${mfg}</span>
      <span class="toc-item-count">${count} models</span>
    </div>
  `;
});

html += `
  </div>
</div>
`;

// Manufacturer Sections
manufacturers.forEach((mfg, index) => {
  const models = groupedMiners[mfg];
  const breakClass = index > 0 ? 'class="page-break"' : '';

  // Calculate price range for this manufacturer
  let minPrice = Infinity;
  let maxPrice = -Infinity;
  let priceCount = 0;

  models.forEach(m => {
    if (m.price && m.price !== 'N/A') {
      const priceStr = String(m.price); // Convert to string first
      const priceNum = parseFloat(priceStr.replace(/[^0-9.]/g, ''));
      if (!isNaN(priceNum)) {
        minPrice = Math.min(minPrice, priceNum);
        maxPrice = Math.max(maxPrice, priceNum);
        priceCount++;
      }
    }
  });

  const priceRange = priceCount > 0 ? 
    `$${minPrice.toLocaleString()} - $${maxPrice.toLocaleString()}` : 
    'N/A';

  html += `<h1 ${breakClass}>${mfg}</h1>`;

  // Manufacturer Summary
  html += `
  <div class="manufacturer-summary">
    <div class="summary-item">
      <span class="summary-label">📦 Total Models:</span>
      <span class="summary-value">${models.length}</span>
    </div>
    <div class="summary-item">
      <span class="summary-label">💰 Price Range:</span>
      <span class="summary-value">${priceRange}</span>
    </div>
    <div class="summary-item">
      <span class="summary-label">🏷️ Category:</span>
      <span class="summary-value">${
        mfg === 'Bitmain' || mfg === 'MicroBT' || mfg === 'Canaan' 
          ? 'Bitcoin Mining' 
          : 'Multi-Algorithm'
      }</span>
    </div>
  </div>
  `;

  // Models Table
  html += `
  <table>
    <thead>
      <tr>
        <th width="8%">#</th>
        <th width="62%">Model Name</th>
        <th width="30%">Price (USD)</th>
      </tr>
    </thead>
    <tbody>
  `;

  models.forEach((model, idx) => {
    const price = model.price || 'N/A';

    html += `
      <tr>
        <td style="text-align: center; color: #9ca3af;">${idx + 1}</td>
        <td><span class="model-name">${model.name}</span></td>
        <td><span class="price">${price}</span></td>
      </tr>
    `;
  });

  html += `
    </tbody>
  </table>
  `;
});

// Footer Section
html += `
<div class="footer">
  <div class="footer-title">⚠️ Important Disclaimer & Notes</div>

  <div class="footer-notes">
    <ul>
      <li><strong>Pricing:</strong> All prices are approximate and subject to change.</li>
      <li><strong>Profitability:</strong> Mining profitability fluctuates based on network difficulty, cryptocurrency prices, and electricity costs.</li>
      <li><strong>Availability:</strong> Stock availability varies by region .</li>
      <li><strong>Specifications:</strong> Always verify technical specifications with the manufacturer's official documentation.</li>

      <li><strong>Warranty & Support:</strong> Check warranty terms and local support availability before purchasing.</li>
    </ul>
  </div>

  <div class="footer-copyright">
    <p><strong>Cryptominer AE Catalog</strong></p>
    <p>Document Generated: ${generatedDate}</p>
    <p>© ${new Date().getFullYear()} All Rights Reserved</p>
    <p style="margin-top: 10px; font-size: 8pt;">
      This document is for informational purposes only. No warranties or guarantees are provided.
    </p>
  </div>
</div>
`;

// Close HTML
html += `
</body>
</html>
`;

// Generate filename
const filename = `ASIC_Miners_Catalog_${new Date().toISOString().split('T')[0]}`;

// Return the complete HTML document in the format expected by Convert to PDF Binary node
return {
  json: {
    filename: filename,
    data: html,
    totalModels: totalCount,
    totalManufacturers: manufacturers.length,
    generatedDate: generatedDate
  }
};

const miners = $input.all().map(item => item.json);
// Get the SessionID (Phone Number) from the start of the workflow
const sessionID = $('When Executed by Another Workflow').first().json.SessionID;

const groupedMiners = {};
const manufacturerOrder = ['Bitmain', 'MicroBT', 'Canaan', 'IceRiver', 'Goldshell', 'Whatsminer', 'Jasminer', 'Innosilicon', 'Bitaxe', 'iPollo', 'Antminer', 'Avalon', 'Other'];

miners.forEach(miner => {
  const name = miner.name || miner.name_lower || 'Unknown';
  let manufacturer = miner.manufacturer || 'Other';
  manufacturer = manufacturer.charAt(0).toUpperCase() + manufacturer.slice(1);

  if (!groupedMiners[manufacturer]) groupedMiners[manufacturer] = [];

  groupedMiners[manufacturer].push({
    name: name,
    price: miner.Price || 'N/A' // Keeping only Price as you requested
  });
});

const sortedManufacturers = Object.keys(groupedMiners).sort(); // Simplified sort

return {
  json: {
    sessionID: sessionID, // <--- PASSING THE PHONE NUMBER
    groupedMiners: groupedMiners,
    manufacturers: sortedManufacturers,
    totalCount: miners.length,
    generatedDate: new Date().toLocaleDateString('en-US')
  }
};

const text = $input.item.json.text || '{}';
const start = text.indexOf('{');
const end = text.lastIndexOf('}');

if (start > -1 && end > -1) {
  try {
    const parsed = JSON.parse(text.substring(start, end + 1));
    return parsed;
  } catch (e) {
    console.error('Parse error:', e);
    return { type: 'general_search', limit: 20 };
  }
} else {
  return { type: 'general_search', limit: 20 };
}

const miners = $('Read DB - Model Detail').all().map(item => item.json);
const routerData = $('Parse Router').first().json;
let modelQuery = (routerData.model_name || '').toLowerCase().trim();

const removeWords = /\b(miner|asic|the|model|about|details|specs?|info|tell me|show me)\b/gi;
modelQuery = modelQuery.replace(removeWords, '').replace(/\s+/g, ' ').trim();

if (!modelQuery) {
  return { 
    json: {
      error: true,
      output: '❌ Please specify which miner model you want details about.'
    }
  };
}

let bestMatch = null;
let highestScore = 0;

for (const miner of miners) {
  if (!miner.name_lower) continue;

  const minerName = miner.name_lower.toString().toLowerCase();
  const cleanMinerName = minerName.replace(removeWords, '').replace(/\s+/g, ' ').trim();

  let score = 0;

  if (cleanMinerName === modelQuery || minerName === modelQuery) {
    score = 1000;
  } else if (cleanMinerName.includes(modelQuery)) {
    score = 800 - (cleanMinerName.length - modelQuery.length);
  } else if (modelQuery.includes(cleanMinerName)) {
    score = 750 - (modelQuery.length - cleanMinerName.length);
  } else {
    const queryWords = modelQuery.split(/[\s\-_]+/).filter(w => w.length > 1);
    const nameWords = cleanMinerName.split(/[\s\-_]+/).filter(w => w.length > 1);

    let matchedWords = 0;
    for (const qWord of queryWords) {
      if (nameWords.some(nw => nw.includes(qWord) || qWord.includes(nw))) {
        matchedWords++;
      }
    }

    if (matchedWords >= queryWords.length * 0.5) {
      score = matchedWords * 100;
    }
  }

  if (score > highestScore) {
    highestScore = score;
    bestMatch = miner;
  }
}

if (!bestMatch || highestScore < 100) {
  return { 
    json: {
      error: true,
      output: `❌ Couldn't find model "${routerData.model_name}". Try:\n• Check spelling\n• Use official model name\n• Ask to see all models from a manufacturer`
    }
  };
}

return {
  json: {
    matched_product: bestMatch.name,
    url: bestMatch.url,
    slug: bestMatch.slug,
    original_query: routerData.model_name,
    match_score: highestScore,
    error: false
  }
};

const miners = $('Read DB - Manufacturer').all().map(item => item.json);
const routerData = $('Parse Router').first().json;
const manufacturerQuery = (routerData.manufacturer || '').toLowerCase().trim();

if (!manufacturerQuery) {
  return { 
    json: {
      output: '❌ Please specify a manufacturer name.',
      type: 'error'
    }
  };
}

const manufacturerAliases = {
  'bitmain': ['bitmain', 'antminer', 'ant miner', 'ant'],
  'microbt': ['microbt', 'whatsminer', 'whats miner', 'micro bt', 'what'],
  'canaan': ['canaan', 'avalon'],
  'innosilicon': ['innosilicon', 'inno silicon', 'inno'],
  'ebang': ['ebang', 'ebit'],
  'ipollo': ['ipollo', 'i pollo', 'nano labs'],
  'goldshell': ['goldshell', 'gold shell'],
  'iceriver': ['iceriver', 'ice river'],
  'jasminer': ['jasminer', 'jas miner']
};

let targetManufacturer = null;
for (const [key, aliases] of Object.entries(manufacturerAliases)) {
  if (aliases.some(alias => manufacturerQuery.includes(alias) || alias.includes(manufacturerQuery))) {
    targetManufacturer = key;
    break;
  }
}

if (!targetManufacturer) {
  targetManufacturer = manufacturerQuery;
}

const matchedMiners = [];
for (const miner of miners) {
  if (!miner.name_lower) continue;

  const minerName = miner.name_lower.toString().toLowerCase();
  let isMatch = false;

  if (targetManufacturer === 'bitmain') {
    isMatch = minerName.includes('antminer') || minerName.includes('bitmain');
  } else if (targetManufacturer === 'microbt') {
    isMatch = minerName.includes('whatsminer') || minerName.includes('microbt');
  } else if (targetManufacturer === 'canaan') {
    isMatch = minerName.includes('avalon') || minerName.includes('canaan');
  } else if (targetManufacturer === 'ipollo') {
    isMatch = minerName.includes('ipollo');
  } else if (targetManufacturer === 'goldshell') {
    isMatch = minerName.includes('goldshell');
  } else if (targetManufacturer === 'iceriver') {
    isMatch = minerName.includes('iceriver');
  } else if (targetManufacturer === 'jasminer') {
    isMatch = minerName.includes('jasminer');
  } else {
    isMatch = minerName.includes(targetManufacturer);
  }

  if (isMatch) {
    matchedMiners.push({
      name: miner.name || miner.name_lower,
      model: miner.name_lower
    });
  }
}

if (matchedMiners.length === 0) {
  return { 
    json: {
      output: `❌ No miners found for "${manufacturerQuery}". Try: Bitmain, MicroBT, Canaan, iPollo, Goldshell, IceRiver, Jasminer.`,
      type: 'error'
    }
  };
}

const sortedMiners = matchedMiners.sort((a, b) => a.name.localeCompare(b.name));

let message = `**Found ${sortedMiners.length} models from ${manufacturerQuery.toUpperCase()}:**\n\n`;
sortedMiners.forEach((miner) => {
  message += `• ${miner.name}\n`;
});
message += `\n💡 **Which model would you like details about?**`;

return {
  json: {
    output: message,
    type: 'manufacturer_list',
    manufacturer: manufacturerQuery,
    models: sortedMiners,
    count: sortedMiners.length
  }
};

// Get data from Airtable
const miners = $('Read DB - Price Range').all().map(item => item.json);
const routerData = $('Parse Router').first().json;
const minPrice = parseFloat(routerData.minPrice) || 0;
const maxPrice = parseFloat(routerData.maxPrice) || 999999;

console.log('Router Data:', routerData);
console.log('Total miners from DB:', miners.length);
console.log('Price range:', minPrice, '-', maxPrice);

// Function to extract numeric price from various formats
function extractPrice(miner) {
  // Check all possible price field names
  const priceFields = ['price', 'Price', 'cost', 'Cost', 'Price ($)', 'price_usd'];

  for (const field of priceFields) {
    if (miner[field]) {
      const priceStr = String(miner[field])
        .replace(/[$€£¥,\s]/g, '')
        .replace(/[^\d.]/g, '');
      const price = parseFloat(priceStr);
      if (price > 0) {
        console.log(`Found price ${price} in field "${field}" for ${miner.name || miner.name_lower}`);
        return price;
      }
    }
  }

  return 0;
}

const filteredMiners = [];
const allPrices = [];

for (const miner of miners) {
  const price = extractPrice(miner);

  if (price > 0) {
    allPrices.push(price);

    if (price >= minPrice && price <= maxPrice) {
      filteredMiners.push({
        name: miner.name || miner.name_lower || 'Unknown',
        price: `$${price.toLocaleString('en-US', {minimumFractionDigits: 0, maximumFractionDigits: 0})}`,
        hashrate: miner.hashrate || miner.Hashrate || 'N/A',
        power: miner.power || miner.consumption || miner.Power || miner.Consumption || 'N/A',
        algorithm: miner.algorithm || miner.Algorithm || 'N/A',
        url: miner.url || miner.URL || '',
        raw_price: price
      });
    }
  }
}

console.log('Filtered miners:', filteredMiners.length);

// If no miners found, provide helpful error
if (filteredMiners.length === 0) {
  allPrices.sort((a, b) => a - b);
  const minAvailable = allPrices[0] || 0;
  const maxAvailable = allPrices[allPrices.length - 1] || 0;

  let errorMsg = `❌ No miners found between $${minPrice.toLocaleString()} - $${maxPrice.toLocaleString()}.\n\n`;

  if (allPrices.length > 0) {
    errorMsg += `💡 **Available price range:** $${minAvailable.toLocaleString()} - $${maxAvailable.toLocaleString()}\n\n`;
    errorMsg += `**Try these ranges:**\n`;
    errorMsg += `• Under $5,000\n`;
    errorMsg += `• $5,000 - $10,000\n`;
    errorMsg += `• $10,000 - $20,000\n`;
    errorMsg += `• Over $20,000`;
  } else {
    errorMsg += `⚠️ **No price data found in database.**\n`;
    errorMsg += `Please check:\n`;
    errorMsg += `• Airtable has a "price" or "Price" column\n`;
    errorMsg += `• Price values are numbers or currency format\n`;
    errorMsg += `• The correct table is selected`;
  }

  return {
    json: {
      output: errorMsg,
      type: 'error',
      debug: {
        minersChecked: miners.length,
        pricesFound: allPrices.length,
        requestedRange: `${minPrice}-${maxPrice}`,
        availableRange: allPrices.length > 0 ? `${minAvailable}-${maxAvailable}` : 'none'
      }
    }
  };
}

// Sort by price
const sortedMiners = filteredMiners.sort((a, b) => a.raw_price - b.raw_price);
const limitedMiners = sortedMiners.slice(0, 30);

let message = `**💰 Found ${filteredMiners.length} miners between $${minPrice.toLocaleString()} - $${maxPrice.toLocaleString()}**\n\n`;

limitedMiners.forEach((miner, idx) => {
  message += `**${idx + 1}. ${miner.name}**\n`;
  message += `   💵 Price: ${miner.price}\n`;
});

if (filteredMiners.length > 30) {
  message += `\n_Showing top 30 of ${filteredMiners.length} results_\n`;
}

message += `\n💡 **Need more info?**\n• Ask for details: "tell me about [model name]"\n• Compare models: "compare [model 1] vs [model 2]"`;

return {
  json: {
    output: message,
    type: 'price_range_list',
    minPrice: minPrice,
    maxPrice: maxPrice,
    models: limitedMiners,
    count: filteredMiners.length
  }
};

const miners = $('Read DB - Best ROI').all().map(item => item.json);
const routerData = $('Parse Router').first().json;
const constraints = routerData.constraints || {};

let candidateMiners = [...miners];

if (constraints.manufacturer) {
  const mfg = constraints.manufacturer.toLowerCase();
  candidateMiners = candidateMiners.filter(m => {
    const name = (m.name_lower || m.name || '').toLowerCase();
    return name.includes(mfg);
  });
}

if (candidateMiners.length === 0) {
  return {
    json: {
      output: '❌ No miners found matching your criteria.',
      type: 'error'
    }
  };
}

const topCandidates = candidateMiners.slice(0, 15);

let message = `🔍 **Best ROI Analysis**\n\n`;
message += `To accurately compare ROI, I need real-time profitability data.\n\n`;
message += `**Top miners to consider:**\n\n`;

topCandidates.forEach((miner, idx) => {
  const name = miner.name || miner.name_lower || 'Unknown';
  message += `${idx + 1}. ${name}\n`;
});

