function findBestMatch(queryModel, allMiners) {
  let modelQuery = (queryModel || '').toLowerCase().trim();
  const removeWords = /\b(miner|asic|the|model|about|details|specs?|info|tell me|show me|vs|versus|or|and|compare|difference|between|better)\b/gi;
  modelQuery = modelQuery.replace(removeWords, '').replace(/\s+/g, ' ').trim();

  let bestMatch = null;
  let highestScore = 0;

  for (const miner of allMiners) {
    if (!miner.name_lower) continue;

    const minerName = miner.name_lower.toString().toLowerCase();
    const cleanMinerName = minerName.replace(removeWords, '').replace(/\s+/g, ' ').trim();

    let score = 0;

    if (cleanMinerName === modelQuery || minerName === modelQuery) {
      score = 1000;
    } else if (cleanMinerName.includes(modelQuery)) {
      score = 800 - (cleanMinerName.length - modelQuery.length);
    } else if (modelQuery.includes(cleanMinerName)) {
      score = 750 - (modelQuery.length - cleanMinerName.length);
    } else {
      const queryWords = modelQuery.split(/[\s\-_]+/).filter(w => w.length > 1);
      const nameWords = cleanMinerName.split(/[\s\-_]+/).filter(w => w.length > 1);
      let matchedWords = 0;
      let partialMatches = 0;
      for (const qWord of queryWords) {
        let wordMatched = false;
        for (const nWord of nameWords) {
          if (nWord === qWord) { matchedWords++; wordMatched = true; break; }
          else if (nWord.includes(qWord) || qWord.includes(nWord)) { partialMatches++; wordMatched = true; break; }
        }
        if (!wordMatched) matchedWords -= 0.5;
      }
      const matchRatio = (matchedWords + (partialMatches * 0.5)) / queryWords.length;
      if (queryWords.length > 0 && matchRatio >= 0.4) {
         score = (matchedWords * 100) + (partialMatches * 50);
      }
    }

    if (score > highestScore) {
      highestScore = score;
      bestMatch = miner;
    }
  }
  return { match: bestMatch, score: highestScore };
}

